int beautySum(char *s) {
    int n = 0;
    while (s[n] != '\0') n++;   // faster than strlen repeatedly

    int total = 0;

    for (int i = 0; i < n; i++) {
        int freq[26] = {0};
        int distinct = 0;

        for (int j = i; j < n; j++) {
            int idx = s[j] - 'a';
            if (freq[idx] == 0) distinct++;
            freq[idx]++;

            int maxFreq = 0;
            int minFreq = n;   // max possible length

            // only 26 chars, but fewer branches
            for (int k = 0; k < 26; k++) {
                if (freq[k]) {
                    if (freq[k] > maxFreq) maxFreq = freq[k];
                    if (freq[k] < minFreq) minFreq = freq[k];
                }
            }

            total += (maxFreq - minFreq);
        }
    }

    return total;
}

