function beautySum(s) {
    const n = s.length;
    let total = 0;

    for (let i = 0; i < n; i++) {
        const freq = new Array(26).fill(0);

        for (let j = i; j < n; j++) {
            const idx = s.charCodeAt(j) - 97;
            freq[idx]++;

            let maxFreq = 0;
            let minFreq = n;

            for (let k = 0; k < 26; k++) {
                if (freq[k] > 0) {
                    if (freq[k] > maxFreq) maxFreq = freq[k];
                    if (freq[k] < minFreq) minFreq = freq[k];
                }
            }

            total += (maxFreq - minFreq);
        }
    }

    return total;
}
